<?php
declare(strict_types=1);
namespace Modules\Accounting\Application\Services;
use Modules\Accounting\Application\Support\AccountingTime;
use Illuminate\Support\Facades\DB;
use Modules\Accounting\Application\DTOs\PostingPreview;
use Modules\Accounting\Application\DTOs\PostingRequest;
use Modules\Accounting\Application\DTOs\PostingResult;
use Modules\Accounting\Application\DTOs\ReversalRequest;
use Modules\Accounting\Domain\Models\Document;
use Modules\Accounting\Domain\Repositories\Contracts\DocumentRepositoryInterface;
use Modules\Accounting\Domain\Repositories\Contracts\JournalLineRepositoryInterface;
use Modules\Accounting\Domain\Repositories\Contracts\JournalRepositoryInterface;
use Modules\Accounting\Domain\Repositories\Contracts\PeriodRepositoryInterface;
use Modules\Accounting\Domain\Repositories\Contracts\PostingLogRepositoryInterface;
use Modules\Accounting\Domain\Services\Contracts\PostingEngineInterface;
final class PostingEngine implements PostingEngineInterface { public function __construct(private readonly DocumentEngine $documents, private readonly JournalEngine $journals, private readonly LedgerEngine $ledger, private readonly PostingLogRepositoryInterface $postingLogs, private readonly PeriodRepositoryInterface $periods, private readonly JournalRepositoryInterface $journalRepository, private readonly JournalLineRepositoryInterface $journalLines, private readonly DocumentRepositoryInterface $documentRepository) {} public function submit(PostingRequest $request): PostingResult { $existing=$this->postingLogs->findByIdempotencyKey($request->idempotencyKey); if($existing!==null && $existing->journal_id!==null){return PostingResult::ok((string)$existing->journal_id,$existing->response_payload['document_number']??null,['idempotent'=>true]);} $preview=$this->preview($request); if($preview->errors!==[]){$this->recordFailure($request,$preview->errors);return PostingResult::failed($preview->errors);} $period=$this->periods->findOpenForDate($request->companyId,$request->postingDate); if($period===null){$errors=['Period must be open for posting date.'];$this->recordFailure($request,$errors);return PostingResult::failed($errors);} return DB::transaction(function() use($request,$preview,$period): PostingResult { $document=$this->documents->ensureApprovedDocument($request); if(!in_array($document->status,[Document::STATUS_APPROVED,Document::STATUS_POSTED],true)){return PostingResult::failed(['Document lifecycle violation: must be approved before posting.']);} $number=$document->document_number ?? sprintf('%s/%s/%06d',strtoupper($request->voucherType),date('Y',strtotime($request->postingDate)),random_int(1,999999)); $journalId=$this->journals->createPostedJournal($request,(string)$document->id,$number,$preview->lines); $this->ledger->applyJournal(['organization_id'=>$request->organizationId,'company_id'=>$request->companyId,'branch_id'=>$request->branchId,'department_id'=>$request->departmentId,'period_id'=>$period->id,'currency'=>$request->currency],$preview->lines); $posted=$this->documents->markPosted($document,$number); $log=$this->postingLogs->findByIdempotencyKey($request->idempotencyKey) ?? $this->postingLogs->create(['organization_id'=>$request->organizationId,'company_id'=>$request->companyId,'branch_id'=>$request->branchId,'department_id'=>$request->departmentId,'idempotency_key'=>$request->idempotencyKey,'source_module'=>$request->sourceModule,'source_document_type'=>$request->sourceDocumentType,'source_document_id'=>$request->sourceDocumentId,'status'=>'posted','request_payload'=>$request->toArray()]); $this->postingLogs->update($log,['document_id'=>$posted->id,'journal_id'=>$journalId,'status'=>'posted','response_payload'=>['document_number'=>$number],'processed_at'=>AccountingTime::now(),'error_message'=>null]); return PostingResult::ok($journalId,$number); }); } public function reverse(ReversalRequest $request): PostingResult { $journal=$this->journalRepository->find($request->journalId); if($journal===null){return PostingResult::failed(['Original journal not found.']);} $lines=$this->journalLines->byJournal($request->journalId); $reversal=[]; foreach($lines as $line){$reversal[]=['account_id'=>$line['account_id'],'debit'=>(string)($line['credit_amount']??'0'),'credit'=>(string)($line['debit_amount']??'0'),'dimensions'=>$line['dimensions']??[],'description'=>'Reversal: '.$request->reason];} $result=$this->submit(new PostingRequest($request->idempotencyKey,'Accounting','journal_reversal',$request->journalId,$request->companyId,$request->organizationId,$request->branchId,$request->departmentId,date('Y-m-d'),(string)$journal->currency,(string)$journal->exchange_rate,'RV',$reversal,$request->reason,(string)$journal->document_id)); if($result->success){$doc=$this->documentRepository->find((string)$journal->document_id); if($doc!==null){$this->documents->markReversed($doc);}} return $result; } public function preview(PostingRequest $request): PostingPreview { $debit='0';$credit='0';$errors=[];$lines=[]; foreach($request->lines as $i=>$line){$dr=(string)($line['debit']??'0');$cr=(string)($line['credit']??'0'); if(($line['account_id']??null)===null || (string)$line['account_id']===''){ $errors[]='Line '.($i+1).' account_id is required.'; continue; } if(MoneyMath::cmp($dr,'0')>0 && MoneyMath::cmp($cr,'0')>0){$errors[]='Line '.($i+1).' cannot have both debit and credit.';} $debit=MoneyMath::add($debit,$dr);$credit=MoneyMath::add($credit,$cr); $lines[]=['account_id'=>(string)$line['account_id'],'debit'=>$dr,'credit'=>$cr,'dimensions'=>(array)($line['dimensions']??[]),'cost_center_id'=>$line['cost_center_id']??null,'profit_center_id'=>$line['profit_center_id']??null,'description'=>$line['description']??null]; } if(count($lines)<2){$errors[]='Minimum 2 lines per journal.';} if(MoneyMath::cmp($debit,$credit)!==0){$errors[]='Double-entry violation: debit must equal credit.';} return new PostingPreview($errors===[],$debit,$credit,$lines,$errors); } private function recordFailure(PostingRequest $request,array $errors): void { $log=$this->postingLogs->findByIdempotencyKey($request->idempotencyKey) ?? $this->postingLogs->create(['organization_id'=>$request->organizationId,'company_id'=>$request->companyId,'branch_id'=>$request->branchId,'department_id'=>$request->departmentId,'idempotency_key'=>$request->idempotencyKey,'source_module'=>$request->sourceModule,'source_document_type'=>$request->sourceDocumentType,'source_document_id'=>$request->sourceDocumentId,'status'=>'failed','request_payload'=>$request->toArray()]); $this->postingLogs->update($log,['status'=>'failed','error_message'=>implode('; ',$errors),'processed_at'=>AccountingTime::now()]); } }

